const pairs = $input.all().map(i => i.json);
const runId = $('Start Ingest Run').first().json.id;
const awards = [];
const seen = new Set();
const sleep = (ms) => new Promise(r => setTimeout(r, ms));

function agencyMatches(rowAgency, pairAgency) {
  if (!pairAgency || !rowAgency) return true;
  const a = String(rowAgency).toLowerCase();
  const b = String(pairAgency).toLowerCase();
  return a.includes(b) || b.includes(a);
}

for (const pair of pairs) {
  const body = {
    filters: {
      time_period: [{ start_date: '2021-01-01', end_date: '2026-12-31' }],
      naics_codes: { require: [pair.naics_code] },
      award_type_codes: ['A', 'B', 'C', 'D'],
    },
    fields: ['Award ID', 'Recipient Name', 'Award Amount', 'Start Date', 'Awarding Agency', 'NAICS Code', 'PSC Code'],
    page: 1,
    limit: 25,
    sort: 'Award Amount',
    order: 'desc',
  };
  try {
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.usaspending.gov/api/v2/search/spending_by_award/',
      body,
      json: true,
    });
    for (const row of res.results || []) {
      const awardId = row['Award ID'] || row['generated_internal_id'] || null;
      if (!awardId || seen.has(awardId)) continue;
      const rowAgency = row['Awarding Agency'] || '';
      if (!agencyMatches(rowAgency, pair.awarding_agency)) continue;
      seen.add(awardId);
      awards.push({
        awarding_agency: rowAgency || pair.awarding_agency,
        naics_code: row['NAICS Code'] || pair.naics_code,
        psc_code: row['PSC Code'] || null,
        recipient_name: row['Recipient Name'] || null,
        award_amount: row['Award Amount'] ?? null,
        award_date: row['Start Date'] || null,
        usaspending_award_id: awardId,
        raw_data: row,
        ingest_run_id: runId,
      });
    }
  } catch (e) {
    console.error(`USAspending failed for ${pair.naics_code}/${pair.awarding_agency}:`, e);
  }
  await sleep(350);
}

return awards.map(a => ({ json: a }));
